1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_PREMIUM = 60;
18	
19	const isBlockOfAlikeRunes = (items: Item[]): boolean =>
20	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === "rune");
21	
22	const sumOfBasePremiums = (items: Item[]): number =>
23	  items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
24	
25	const basePremium = (items: Item[]): number =>
26	  isBlockOfAlikeRunes(items) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(items);
27	
28	const percentOf = (amount: number, percent: number): number =>
29	  (amount * percent) / 100;
30	
31	const firstInsuranceSurcharge = (base: number): number =>
32	  Math.ceil(percentOf(base, FIRST_INSURANCE_SURCHARGE_PERCENT));
33	
34	const quotePremium = (items: Item[]): number => {
35	  const base = basePremium(items);
36	  return base + firstInsuranceSurcharge(base) + PROCESSING_FEE;
37	};
38	
39	const executeStep = ({ items }: Step) => ({ premium: quotePremium(items) });
40	
41	export const run = (input: unknown): unknown => {
42	  const { steps } = input as Input;
43	  return { results: steps.map(executeStep) };
44	};
