1	import { describe, it, expect } from "vitest";
2	import { run } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge cases: empty / processing fee only ---
6	  it("empty item list yields premium 5 G (processing fee only)", () => {
7	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [] }] });
8	    expect(out).toEqual({ results: [{ premium: 5 }] });
9	  });
10	
11	  // --- Base premiums per main item type ---
12	  it("quote for a single plain sword (new customer, 1st contract) → 100 base + 10 first-ins + 5 fee = 115 G", () => {
13	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "sword" }] }] });
14	    expect(out).toEqual({ results: [{ premium: 115 }] });
15	  });
16	  it("quote for a single plain amulet (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
17	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "amulet" }] }] });
18	    expect(out).toEqual({ results: [{ premium: 71 }] });
19	  });
20	  it("quote for a single plain staff (new customer, 1st contract) → 80 base + 8 first-ins + 5 fee = 93 G", () => {
21	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "staff" }] }] });
22	    expect(out).toEqual({ results: [{ premium: 93 }] });
23	  });
24	  it("quote for a single plain potion (new customer, 1st contract) → 40 base + 4 first-ins + 5 fee = 49 G", () => {
25	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "potion" }] }] });
26	    expect(out).toEqual({ results: [{ premium: 49 }] });
27	  });
28	
29	  // --- Components base premium (per-component default) ---
30	  it("quote for 2 runes (new customer, 1st contract) → 50 base + 5 first-ins + 5 fee = 60 G", () => {
31	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }] });
32	    expect(out).toEqual({ results: [{ premium: 60 }] });
33	  });
34	
35	  // --- Building block of 3 alike components ---
36	  it("quote for 3 runes (block) (new customer, 1st contract) → 60 base + 6 first-ins + 5 fee = 71 G", () => {
37	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
38	    expect(out).toEqual({ results: [{ premium: 71 }] });
39	  });
40	  it("quote for 4 runes (no block) → 100 base + 10 first-ins + 5 fee = 115 G", () => {
41	    const out = run({ customer: { yearsWithMHPCO: 0 }, steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }] });
42	    expect(out).toEqual({ results: [{ premium: 115 }] });
43	  });
44	  it("quote for 7 runes (no block — block requires exactly 3) → 175 base + 18 first-ins + 5 fee = 198 G", () => {
45	    const out = run({
46	      customer: { yearsWithMHPCO: 0 },
47	      steps: [{ op: "quote", items: Array(7).fill({ type: "rune" }) }],
48	    });
49	    expect(out).toEqual({ results: [{ premium: 198 }] });
50	  });
51	
52	  // --- 'Alike' components clarified by type ---
53	  it.todo("quote for 2 runes + 1 moonstone → 75 G base premium (no block: different types) (+5 fee = 80)");
54	  it.todo("quote for 3 runes + 3 moonstones → 120 G base premium (two separate blocks) (+5 fee = 125)");
55	
56	  // --- Single-modifier surcharges/discounts on a single item ---
57	  it.todo("cursed sword alone (new customer, 1st contract) → 100 base + 50 curse + 10 first-ins + 5 fee = 165 G");
58	  it.todo("high-enchantment sword (enchantment 5) alone (new customer, 1st contract) → 100 + 30 + 10 + 5 = 145 G");
59	  it.todo("sword with enchantment 4 alone (new customer, 1st contract) → no high-ench surcharge → 115 G");
60	
61	  // --- Modifier thresholds ---
62	  it.todo("customer with exactly 2 years gets loyalty discount (plain sword, 1st contract) → 100 - 20 + 10 + 5 = 95 G");
63	  it.todo("cursed sword with exactly enchantment 5 gets both surcharges → 100 + 50 + 30 + 10 + 5 = 195 G");
64	
65	  // --- Multi-item policy & modifier scope ---
66	  it.todo("cursed sword + plain amulet (new customer, 1st contract) → 100+60 base, cursed adds 50 (of sword only), first-ins 10% of policy total → 160 + 50 + 16 + 5 = 231 G");
67	
68	  // --- Follow-up contract discount (15% on each contract after first) ---
69	  it.todo("second quote in scenario: cursed sword + plain amulet, 0 years → first ins still 10%, follow-up 15% off policy total");
70	
71	  // --- Integration examples ---
72	  it.todo("newcomer cursed sword (0 years, no prior): 100 + 50 + 10 + 5 = 165 G");
73	  it.todo("long-standing customer's 2nd contract, cursed enchantment-7 sword (3 years): 100 + 50 + 30 - 20 + 10 - 15 + 5 = 160 G");
74	
75	  // --- Rounding in MHPCO's favor ---
76	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
77	
78	  // --- Claim: basic deductible & standard reimbursement ---
79	  it.todo("steel sword enchantment 3, damage 500 → payout 400 (500 - 100 deductible)");
80	  it.todo("damage to a rune (250 G), damage 200 → payout 100 (200 - 100 deductible)");
81	
82	  // --- Claim: high-enchantment 50% clause ---
83	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 (50% then deductible: 500 - 100)");
84	
85	  // --- Claim: dragon material full reimbursement ---
86	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 (full minus deductible)");
87	
88	  // --- Claim: dragon + high enchantment combined (50% wins) ---
89	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 (high-ench applies first then deductible)");
90	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
91	
92	  // --- Claim: deductible per damage event ---
93	  it.todo("dragon attack damages insured sword 500 and amulet 300 → payout 600 (deductible applies once per damaged item)");
94	
95	  // --- Multiple items of same type ---
96	  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G; two sword damage entries each get own deductible");
97	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero (claim rejected)");
98	
99	  // --- Cap exhaustion ---
100	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
101	  it.todo("cursed sword cap is 2000 G (based on unmodified insurance value, premium modifiers do not raise cap)");
102	  it.todo("sword + 3 runes block: insurance sum 1750 G (block discount affects premium only, not insurance sum)");
103	  it.todo("sword (cap 2000): claim 1500 → payout 1400, remainingCap 600; second claim 1500 → payout 600, remainingCap 0");
104	
105	  // --- Rounding payout ---
106	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
107	
108	  // --- Error cases ---
109	  it.todo("quote with unknown item type (e.g. broomstick) → CLI exits non-zero with error to stderr");
110	  it.todo("claim references damage entry whose item is not in policy → CLI exits non-zero");
111	  it.todo("claim contains damage entry with negative amount → CLI exits non-zero");
112	});
